#include<bits/stdc++.h>
using namespace std;

int main() {
    int n, m, ansl = 0, ansr = 2e9;
    cin >> n >> m;
    for(int i = 1; i <= n; i++) {
        int a;
        cin >> a;
        int l = m / (i * a);
        if(m % (i * a) > 0) l++;
        int r = a > 1 ? m / (i * (a - 1)) - !(m % (i * (a - 1))) : 2e9;
        ansl = max(ansl, l);
        ansr = min(ansr, r);
    }
    if(ansr == 2e9) cout << "xiaogougege";
    else cout << max(0, ansr - ansl + 1);
}
